with open('d:/IG/TOOL/WEB/P1.html', 'w', encoding='utf-8') as h_file:
    h_file.write('<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>Blueprint Fitness Assessment</title>\n<link href="https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,400;0,500;0,600;1,400&family=DM+Sans:wght@300;400;500&display=swap" rel="stylesheet">\n<style>\n  :root {\n    --bg: #0d0d0d;\n    --surface: #161616;\n    --surface2: #1e1e1e;\n    --border: rgba(255,255,255,0.08);\n    --border-active: rgba(201,168,76,0.6);\n    --gold: #C9A84C;\n    --gold-light: #e2c572;\n    --text: #f0ece4;\n    --muted: #888880;\n    --label: #b0aca4;\n    --danger: #e05c5c;\n    --success: #5cb88a;\n    --progress-h: 3px;\n    --radius: 10px;\n    --section-colors: #C9A84C, #7eb8e0, #c97e7e, #7ec9a0, #c97eb8, #7e9ec9;\n  }\n  * { box-sizing: border-box; margin: 0; padding: 0; }\n  body {\n    background: var(--bg);\n    color: var(--text);\n    font-family: \'DM Sans\', sans-serif;\n    font-weight: 300;\n    min-height: 100vh;\n    line-height: 1.6;\n  }\n  /* Progress bar */\n  #progress-bar-wrap {\n    position: fixed; top: 0; left: 0; width: 100%; z-index: 100;\n    height: var(--progress-h); background: rgba(255,255,255,0.05);\n  }\n  #progress-fill {\n    height: 100%; background: var(--gold);\n    transition: width 0.4s ease;\n    width: 0%;\n  }\n  /* Header */\n  header {\n    padding: 3rem 2rem 2rem;\n    max-width: 760px; margin: 0 auto;\n    border-bottom: 0.5px solid var(--border);\n    text-align: center;\n  }\n  header .eyebrow {\n    font-size: 11px; letter-spacing: 0.2em; text-transform: uppercase;\n    color: var(--gold); margin-bottom: 1rem; font-family: \'DM Sans\', sans-serif; font-weight: 400;\n  }\n  header h1 {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: clamp(2rem, 5vw, 3rem);\n    font-weight: 500; color: var(--text);\n    line-height: 1.15; margin-bottom: 0.75rem;\n  }\n  header p {\n    font-size: 14px; color: var(--muted); max-width: 480px; margin: 0 auto;\n  }\n  /* Section tabs */\n  #section-nav {\n    max-width: 760px; margin: 0 auto;\n    display: flex; gap: 6px; padding: 1.5rem 2rem 0;\n    overflow-x: auto; scrollbar-width: none;\n  }\n  #section-nav::-webkit-scrollbar { display: none; }\n  .sec-tab {\n    flex-shrink: 0;\n    padding: 6px 14px; border-radius: 20px;\n    font-size: 12px; font-weight: 400;\n    border: 0.5px solid var(--border);\n    background: transparent; color: var(--muted);\n    cursor: pointer; transition: all 0.2s;\n    letter-spacing: 0.03em;\n  }\n  .sec-tab.active { background: var(--gold); color: #0d0d0d; border-color: var(--gold); font-weight: 500; }\n  .sec-tab.done { border-color: rgba(92,184,138,0.4); color: var(--success); }\n  /* Main form */\n  main { max-width: 760px; margin: 0 auto; padding: 0 2rem 6rem; }\n  /* Section block */\n  .section-block {\n    display: none;\n    padding: 2rem 0;\n    animation: fadeIn 0.3s ease;\n  }\n  .section-block.visible { display: block; }\n  @keyframes fadeIn { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }\n  .section-header {\n    display: flex; align-items: center; gap: 12px;\n    margin-bottom: 2rem; padding-bottom: 1rem;\n    border-bottom: 0.5px solid var(--border);\n  }\n  .section-badge {\n    width: 32px; height: 32px; border-radius: 50%;\n    display: flex; align-items: center; justify-content: center;\n    font-size: 12px; font-weight: 500; flex-shrink: 0;\n  }\n  .section-header h2 {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: 1.5rem; font-weight: 500; color: var(--text);\n  }\n  .section-header p { font-size: 12px; color: var(--muted); margin-top: 2px; }\n  /* Question card */\n  .q-card {\n    background: var(--surface);\n    border: 0.5px solid var(--border);\n    border-radius: var(--radius);\n    padding: 1.25rem 1.5rem;\n    margin-bottom: 1rem;\n    transition: border-color 0.2s;\n  }\n  .q-card:focus-within { border-color: var(--border-active); }\n  .q-label {\n    font-size: 13px; font-weight: 400; color: var(--label);\n    margin-bottom: 0.75rem; display: flex; align-items: baseline; gap: 8px;\n  }\n  .q-num {\n    font-size: 10px; font-weight: 500; letter-spacing: 0.1em;\n    color: var(--gold); text-transform: uppercase; flex-shrink: 0;\n  }\n  .q-text { color: var(--text); font-size: 14px; font-weight: 400; line-height: 1.5; }\n  .q-hint { font-size: 11px; color: var(--muted); margin-top: 4px; font-style: italic; }\n  /* Inputs */\n  input[type="text"], input[type="number"], textarea, select {\n    width: 100%; background: var(--surface2);\n    border: 0.5px solid var(--border);\n    border-radius: 6px; padding: 10px 12px;\n    color: var(--text); font-family: \'DM Sans\', sans-serif;\n    font-size: 14px; font-weight: 300;\n    transition: border-color 0.2s; outline: none;\n    margin-top: 8px;\n  }\n  input[type="text"]:focus, input[type="number"]:focus,\n  textarea:focus, select:focus {\n    border-color: var(--border-active);\n  }\n  select option { background: #1e1e1e; }\n  textarea { resize: vertical; min-height: 80px; line-height: 1.6; }\n  /* MCQ options */\n  .mcq-grid {\n    display: grid; grid-template-columns: 1fr 1fr;\n    gap: 8px; margin-top: 8px;\n  }\n  .mcq-grid.single { grid-template-columns: 1fr; }\n  .mcq-opt {\n    background: var(--surface2); border: 0.5px solid var(--border);\n    border-radius: 6px; padding: 10px 14px;\n    font-size: 13px; color: var(--muted);\n    cursor: pointer; transition: all 0.15s;\n    user-select: none; line-height: 1.4;\n  }\n  .mcq-opt:hover { border-color: rgba(201,168,76,0.3); color: var(--text); }\n  .mcq-opt.selected {\n    border-color: var(--gold); color: var(--gold-light);\n    background: rgba(201,168,76,0.06);\n  }\n  /* Scale / Rating */\n  .scale-wrap {\n    display: flex; gap: 8px; margin-top: 8px; align-items: center;\n  }\n  .scale-btn {\n    width: 40px; height: 40px; border-radius: 50%;\n    border: 0.5px solid var(--border);\n    background: var(--surface2);\n    color: var(--muted); font-size: 14px; font-weight: 400;\n    cursor: pointer; transition: all 0.15s;\n    display: flex; align-items: center; justify-content: center;\n  }\n  .scale-btn:hover { border-color: rgba(201,168,76,0.3); color: var(--text); }\n  .scale-btn.selected { background: var(--gold); color: #0d0d0d; border-color: var(--gold); font-weight: 500; }\n  .scale-labels {\n    display: flex; justify-content: space-between;\n    margin-top: 4px; font-size: 10px; color: var(--muted);\n  }\n  /* Navigation buttons */\n  .nav-row {\n    display: flex; justify-content: space-between; align-items: center;\n    padding: 1.5rem 0 0; gap: 12px;\n  }\n  .btn {\n    padding: 11px 24px; border-radius: 6px;\n    font-size: 13px; font-weight: 500; font-family: \'DM Sans\', sans-serif;\n    cursor: pointer; transition: all 0.15s; border: 0.5px solid;\n    letter-spacing: 0.02em;\n  }\n  .btn-outline {\n    background: transparent; border-color: var(--border); color: var(--muted);\n  }\n  .btn-outline:hover { border-color: var(--border-active); color: var(--text); }\n  .btn-primary {\n    background: var(--gold); border-color: var(--gold); color: #0d0d0d;\n  }\n  .btn-primary:hover { background: var(--gold-light); border-color: var(--gold-light); }\n  .btn-ghost { background: transparent; border-color: transparent; color: var(--muted); font-size: 12px; }\n  .step-indicator { font-size: 12px; color: var(--muted); }\n  /* Result screen */\n  #result-screen {\n    display: none; padding: 2rem 0;\n    animation: fadeIn 0.4s ease;\n  }\n  #result-screen h2 {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: 2rem; font-weight: 500;\n    margin-bottom: 0.5rem;\n  }\n  #result-screen .sub { font-size: 14px; color: var(--muted); margin-bottom: 2rem; }\n  #output-box {\n    background: var(--surface);\n    border: 0.5px solid var(--border);\n    border-radius: var(--radius);\n    padding: 1.5rem;\n    font-size: 12.5px; line-height: 1.9;\n    color: var(--label); white-space: pre-wrap;\n    font-family: \'DM Sans\', sans-serif;\n    max-height: 60vh; overflow-y: auto;\n    scrollbar-width: thin; scrollbar-color: var(--border) transparent;\n  }\n  .copy-row { display: flex; gap: 10px; margin-top: 1rem; }\n  #copy-btn {\n    padding: 11px 24px; border-radius: 6px; font-size: 13px; font-weight: 500;\n    font-family: \'DM Sans\', sans-serif; cursor: pointer; transition: all 0.2s;\n    background: var(--gold); border: none; color: #0d0d0d;\n  }\n  #copy-btn:hover { background: var(--gold-light); }\n  #copy-btn.copied { background: var(--success); color: #fff; }\n  #restart-btn {\n    padding: 11px 24px; border-radius: 6px; font-size: 13px; font-weight: 400;\n    font-family: \'DM Sans\', sans-serif; cursor: pointer;\n    background: transparent; border: 0.5px solid var(--border); color: var(--muted);\n    transition: all 0.2s;\n  }\n  #restart-btn:hover { border-color: var(--border-active); color: var(--text); }\n  \n  #clear-form-btn {\n    padding: 11px 24px; border-radius: 6px; font-size: 13px; font-weight: 500;\n    font-family: \'DM Sans\', sans-serif; cursor: pointer; transition: all 0.2s;\n    background: transparent; border: 0.5px solid var(--danger); color: var(--danger);\n  }\n  #clear-form-btn:hover {\n    background: rgba(224, 92, 92, 0.1);\n  }\n  \n  .disclaimer {\n    background: rgba(201,168,76,0.05); border: 0.5px solid rgba(201,168,76,0.15);\n    border-radius: 6px; padding: 12px 16px; margin-top: 1.5rem;\n    font-size: 12px; color: var(--muted); line-height: 1.6;\n  }\n  .disclaimer strong { color: var(--gold); }\n  /* Responsive */\n  @media (max-width: 540px) {\n    .mcq-grid { grid-template-columns: 1fr; }\n    header, main, #section-nav { padding-left: 1rem; padding-right: 1rem; }\n  }\n\n  .q-card.invalid {\n    border-color: var(--danger) !important;\n    animation: shake 0.4s cubic-bezier(.36,.07,.19,.97) both;\n  }\n  @keyframes shake {\n    10%, 90% { transform: translate3d(-1px, 0, 0); }\n    20%, 80% { transform: translate3d(2px, 0, 0); }\n    30%, 50%, 70% { transform: translate3d(-4px, 0, 0); }\n    40%, 60% { transform: translate3d(4px, 0, 0); }\n  }\n\n</style>\n</head>\n<body>\n\n<div id="progress-bar-wrap"><div id="progress-fill"></div></div>\n\n<header>\n  <div class="eyebrow">Blueprint Fitness System</div>\n  <h1>Your Personal<br><em>Fitness Assessment</em></h1>\n  <p>30 questions · 6 sections · Takes about 5 minutes. Your answers generate a personalised 12-month blueprint.</p>\n</header>\n\n<div id="section-nav">\n  <button class="sec-tab active" onclick="if(validateSection(0)) goSection(0)">A · Identity</button>\n  <button class="sec-tab" onclick="if(validateSection(0)) goSection(1)">B · Body Type</button>\n  <button class="sec-tab" onclick="if(validateSection(1)) goSection(2)">C · Medical</button>\n  <button class="sec-tab" onclick="if(validateSection(2)) goSection(3)">D · Fitness</button>\n  <button class="sec-tab" onclick="if(validateSection(3)) goSection(4)">E · Goals</button>\n  <button class="sec-tab" onclick="if(validateSection(4)) goSection(5)">F · Lifestyle</button>\n</div>\n\n<main>\n\n<!-- SECTION A -->\n<div class="section-block visible" id="sec-0">\n  <div class="section-header">\n    <div class="section-badge" style="background:rgba(201,168,76,0.12);color:var(--gold);">A</div>\n    <div>\n      <h2>Personal Identity</h2>\n      <p>Basic details to personalise your blueprint</p>\n    </div>\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">A1</span><span class="q-text">What is your name?</span></div>\n    <input type="text" id="A1" placeholder="Your first name or nickname">\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">A2</span><span class="q-text">What is your age?</span></div>\n    <input type="number" id="A2" placeholder="e.g. 22" min="13" max="80">\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">A3</span><span class="q-text">Biological sex</span></div>\n    <div class="mcq-grid">\n      <div class="mcq-opt" data-q="A3" data-val="Male">Male</div>\n      <div class="mcq-opt" data-q="A3" data-val="Female">Female</div>\n    </div>\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">A4</span><span class="q-text">Where are you located? (City / State / Climate)</span></div>\n    <input type="text" id="A4" placeholder="e.g. Kozhikode, Kerala — hot & humid">\n  </div>\n\n  <div class="nav-row">\n    <span class="step-indicator">Section 1 of 6</span>\n    <button class="btn btn-primary" onclick="if(validateSection(0)) goSection(1)">Next →</button>\n  </div>\n</div>\n\n<!-- SECTION B -->\n<div class="section-block" id="sec-1">\n  <div class="section-header">\n    <div class="section-badge" style="background:rgba(126,184,224,0.12);color:#7eb8e0;">B</div>\n    <div>\n      <h2>Body Type Self-Assessment</h2>\n      <p>Helps identify your somatotype for training approach</p>\n    </div>\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">B5</span><span class="q-text">What is your height and current weight?</span></div>\n    <input type="text" id="B5" placeholder="e.g. 172 cm, 68 kg">\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">B6</span><span class="q-text">How does your wrist size feel compared to others of similar height?</span><div class="q-hint">Wrap your thumb and middle finger around your opposite wrist</div></div>\n    <div class="mcq-grid">\n      <div class="mcq-opt" data-q="B6" data-val="Small — fingers overlap easily">Small — fingers overlap easily</div>\n      <div class="mcq-opt" data-q="B6" data-val="Medium — fingers just touch">Medium — fingers just touch</div>\n      <div class="mcq-opt" data-q="B6" data-val="Large — fingers don\'t reach">Large — fingers don\'t reach</div>\n    </div>\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">B7</span><span class="q-text">Describe your shoulder-to-hip ratio</span></div>\n    <div class="mcq-grid">\n      <div class="mcq-opt" data-q="B7" data-val="Narrow shoulders, narrow hips (straight frame)">Narrow shoulders, narrow hips</div>\n      <div class="mcq-opt" data-q="B7" data-val="Broader shoulders than hips (V-shape tendency)">Broader shoulders than hips</div>\n      <div class="mcq-opt" data-q="B7" data-val="Hips and shoulders roughly equal (rectangular)">Hips and shoulders roughly equal</div>\n      <div class="mcq-opt" data-q="B7" data-val="Hips wider than shoulders">Hips wider than shoulders</div>\n    </div>\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">B8</span><span class="q-text">Where does fat accumulate on your body first?</span></div>\n    <div class="mcq-grid">\n      <div class="mcq-opt" data-q="B8" data-val="Mostly abdomen / belly area">Mostly abdomen / belly</div>\n      <div class="mcq-opt" data-q="B8" data-val="Hips, thighs, and lower body">Hips, thighs, lower body</div>\n      <div class="mcq-opt" data-q="B8" data-val="Evenly distributed all over">Evenly all over</div>\n      <div class="mcq-opt" data-q="B8" data-val="I don\'t tend to store visible fat easily">I don\'t store fat easily</div>\n    </div>\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">B9</span><span class="q-text">How does your body respond when you eat more than usual for a week?</span></div>\n    <div class="mcq-grid">\n      <div class="mcq-opt" data-q="B9" data-val="Barely any change — hard to gain weight">Barely any change</div>\n      <div class="mcq-opt" data-q="B9" data-val="Slight weight gain, mostly muscle-looking">Slight gain, looks muscular</div>\n      <div class="mcq-opt" data-q="B9" data-val="Noticeable fat gain quickly">Noticeable fat gain</div>\n    </div>\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">B10</span><span class="q-text">How would you describe your natural frame / build?</span></div>\n    <div class="mcq-grid">\n      <div class="mcq-opt" data-q="B10" data-val="Lean and lanky — naturally thin">Lean and lanky</div>\n      <div class="mcq-opt" data-q="B10" data-val="Athletic and proportionate">Athletic and proportionate</div>\n      <div class="mcq-opt" data-q="B10" data-val="Stocky or broad — solid build">Stocky or broad</div>\n      <div class="mcq-opt" data-q="B10" data-val="Soft / rounded — carries fat easily">Soft / rounded</div>\n    </div>\n  </div>\n\n  <div class="nav-row">\n    <button class="btn btn-outline" onclick="goSection(0)">← Back</button>\n    <span class="step-indicator">Section 2 of 6</span>\n    <button class="btn btn-primary" onclick="if(validateSection(1)) goSection(2)">Next →</button>\n  </div>\n</div>\n\n<!-- SECTION C -->\n<div class="section-block" id="sec-2">\n  <div class="section-header">\n    <div class="section-badge" style="background:rgba(201,126,126,0.12);color:#c97e7e;">C</div>\n    <div>\n      <h2>Medical History</h2>\n      <p>Used only to personalise your plan safely — consult your doctor before starting any program</p>\n    </div>\n  </div>\n\n  <div class="disclaimer"><strong>Medical disclaimer:</strong> This information is used only to customise your fitness plan. If you have any diagnosed condition, please consult your doctor before beginning structured training.</div>\n\n  <div class="q-card" style="margin-top:1rem;">\n    <div class="q-label"><span class="q-num">C11</span><span class="q-text">Do you have any diagnosed medical conditions? (Select all that apply)</span></div>\n    <div class="mcq-grid single" id="C11-multi"></div>\n    <textarea id="C11-other" placeholder="Any other conditions not listed above..." style="margin-top:8px;min-height:60px;"></textarea>\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">C12</span><span class="q-text">Do you have any past or current injuries?</span></div>\n    <textarea id="C12" placeholder="e.g. Left knee ACL (2022), lower back pain (ongoing)... or \'None\'"></textarea>\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">C13</span><span class="q-text">Are you currently taking any medications?</span></div>\n    <input type="text" id="C13" placeholder="List medications, or \'None\'">\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">C14</span><span class="q-text">Any recent surgeries in the last 12 months?</span></div>\n    <div class="mcq-grid">\n      <div class="mcq-opt" data-q="C14" data-val="No recent surgeries">No</div>\n      <div class="mcq-opt" data-q="C14" data-val="Yes — fully recovered">Yes — fully recovered</div>\n      <div class="mcq-opt" data-q="C14" data-val="Yes — still recovering">Yes — still recovering</div>\n    </div>\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">C15</span><span class="q-text">Pregnancy / postpartum status (if applicable)</span></div>\n    <div class="mcq-grid single">\n      <div class="mcq-opt" data-q="C15" data-val="Not applicable">Not applicable</div>\n      <div class="mcq-opt" data-q="C15" data-val="Currently pregnant">Currently pregnant</div>\n      <div class="mcq-opt" data-q="C15" data-val="Postpartum (within 1 year)">Postpartum (within 1 year)</div>\n    </div>\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">C16</span><span class="q-text">Rate your typical daily energy level</span></div>\n    <div class="scale-wrap" id="scale-C16"></div>\n    <div class="scale-labels"><span>Always exhausted</span><span>High energy</span></div>\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">C17</span><span class="q-text">Rate your typical sleep quality</span></div>\n    <div class="scale-wrap" id="scale-C17"></div>\n    <div class="scale-labels"><span>Very poor</span><span>Excellent</span></div>\n  </div>\n\n  <div class="nav-row">\n    <button class="btn btn-outline" onclick="goSection(1)">← Back</button>\n    <span class="step-indicator">Section 3 of 6</span>\n    <button class="btn btn-primary" onclick="if(validateSection(2)) goSection(3)">Next →</button>\n  </div>\n</div>\n\n<!-- SECTION D -->\n<div class="section-block" id="sec-3">\n  <div class="section-header">\n    <div class="section-badge" style="background:rgba(126,201,160,0.12);color:#7ec9a0;">D</div>\n    <div>\n      <h2>Current Fitness Status</h2>\n      <p>Your training history and current activity levels</p>\n    </div>\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">D18</span><span class="q-text">How many years of consistent training experience do you have?</span></div>\n    <div class="mcq-grid single">\n      <div class="mcq-opt" data-q="D18" data-val="Complete beginner — never trained">Complete beginner — never trained</div>\n      <div class="mcq-opt" data-q="D18" data-val="Beginner — less than 1 year">Beginner — less than 1 year</div>\n      <div class="mcq-opt" data-q="D18" data-val="Intermediate — 1 to 3 years">Intermediate — 1 to 3 years</div>\n      <div class="mcq-opt" data-q="D18" data-val="Advanced — more than 3 years">Advanced — more than 3 years</div>\n    </div>\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">D19</span><span class="q-text">Current activity level (outside any formal workout)</span></div>\n    <div class="mcq-grid single">\n      <div class="mcq-opt" data-q="D19" data-val="Sedentary — desk job, mostly sitting">Sedentary — desk job, mostly sitting</div>\n      <div class="mcq-opt" data-q="D19" data-val="Lightly active — some walking daily">Lightly active — some walking</div>\n      <div class="mcq-opt" data-q="D19" data-val="Moderately active — physically involved work or daily movement">Moderately active — physical work</div>\n      <div class="mcq-opt" data-q="D19" data-val="Very active — labour-intensive work or sport">Very active — labour or sport</div>\n    </div>\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">D20</span><span class="q-text">What types of exercise do you currently do, and how often?</span></div>\n    <textarea id="D20" placeholder="e.g. 3x/week gym (chest + back), 1x weekend cricket... or \'Nothing currently\'"></textarea>\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">D21</span><span class="q-text">Describe any previous fitness programs you\'ve tried and the results</span></div>\n    <textarea id="D21" placeholder="e.g. Tried gym for 2 months in 2023, gained some strength but quit due to inconsistency. Tried keto — lost 3kg but couldn\'t sustain..."></textarea>\n  </div>\n\n  <div class="nav-row">\n    <button class="btn btn-outline" onclick="goSection(2)">← Back</button>\n    <span class="step-indicator">Section 4 of 6</span>\n    <button class="btn btn-primary" onclick="if(validateSection(3)) goSection(4)">Next →</button>\n  </div>\n</div>\n\n<!-- SECTION E -->\n<div class="section-block" id="sec-4">\n  <div class="section-header">\n    <div class="section-badge" style="background:rgba(201,126,184,0.12);color:#c97eb8;">E</div>\n    <div>\n      <h2>Goals & Timeline</h2>\n      <p>Define what success looks like for you</p>\n    </div>\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">E22</span><span class="q-text">What is your primary fitness goal?</span></div>\n    <div class="mcq-grid single">\n      <div class="mcq-opt" data-q="E22" data-val="Fat loss — lose body fat and get leaner">Fat loss — lose body fat and get leaner</div>\n      <div class="mcq-opt" data-q="E22" data-val="Muscle gain (bulk) — gain size and strength">Muscle gain (bulk) — gain size and strength</div>\n      <div class="mcq-opt" data-q="E22" data-val="Body recomposition — lose fat AND gain muscle simultaneously">Body recomposition — lose fat and gain muscle</div>\n      <div class="mcq-opt" data-q="E22" data-val="Endurance and stamina improvement">Endurance and stamina improvement</div>\n      <div class="mcq-opt" data-q="E22" data-val="General health, fitness, and energy improvement">General health and energy</div>\n    </div>\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">E23</span><span class="q-text">What is your ideal timeline to see significant results?</span></div>\n    <div class="mcq-grid">\n      <div class="mcq-opt" data-q="E23" data-val="3 months (short-term push)">3 months</div>\n      <div class="mcq-opt" data-q="E23" data-val="6 months (meaningful transformation)">6 months</div>\n      <div class="mcq-opt" data-q="E23" data-val="12 months (complete physique overhaul)">12 months</div>\n      <div class="mcq-opt" data-q="E23" data-val="Long-term lifestyle change — no fixed deadline">Long-term lifestyle</div>\n    </div>\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">E24</span><span class="q-text">Is there a specific event or deadline driving this? (Optional)</span></div>\n    <input type="text" id="E24" placeholder="e.g. Wedding in August, college fest in March, or \'No specific event\'">\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">E25</span><span class="q-text">Which body areas do you most want to improve?</span></div>\n    <div class="mcq-grid" id="E25-multi"></div>\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">E26</span><span class="q-text">I understand that realistic fat loss is 0.5–1 kg/week and muscle gain is 0.5–1 kg/month</span></div>\n    <div class="mcq-grid">\n      <div class="mcq-opt" data-q="E26" data-val="Yes — I have realistic expectations and am ready to be consistent">Yes — I\'m ready to be consistent</div>\n      <div class="mcq-opt" data-q="E26" data-val="I want faster results and am willing to follow the plan strictly">I want fast results and will follow strictly</div>\n    </div>\n  </div>\n\n  <div class="nav-row">\n    <button class="btn btn-outline" onclick="goSection(3)">← Back</button>\n    <span class="step-indicator">Section 5 of 6</span>\n    <button class="btn btn-primary" onclick="if(validateSection(4)) goSection(5)">Next →</button>\n  </div>\n</div>\n\n<!-- SECTION F -->\n<div class="section-block" id="sec-5">\n  <div class="section-header">\n    <div class="section-badge" style="background:rgba(126,158,201,0.12);color:#7e9ec9;">F</div>\n    <div>\n      <h2>Lifestyle & Convenience</h2>\n      <p>So your plan works in your real life, not just on paper</p>\n    </div>\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">F27</span><span class="q-text">What equipment or gym access do you have?</span></div>\n    <div class="mcq-grid single">\n      <div class="mcq-opt" data-q="F27" data-val="Tier 1 — No equipment, bodyweight only at home">Tier 1 — No equipment, bodyweight only</div>\n      <div class="mcq-opt" data-q="F27" data-val="Tier 2 — Resistance bands and/or dumbbells at home">Tier 2 — Resistance bands / dumbbells at home</div>\n      <div class="mcq-opt" data-q="F27" data-val="Tier 3 — Full home gym (barbell, bench, rack)">Tier 3 — Full home gym setup</div>\n      <div class="mcq-opt" data-q="F27" data-val="Tier 4 — Commercial gym access (full machines, cables, barbells)">Tier 4 — Commercial gym access</div>\n    </div>\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">F28</span><span class="q-text">How many days per week can you realistically train?</span></div>\n    <div class="mcq-grid">\n      <div class="mcq-opt" data-q="F28" data-val="2 days/week">2 days</div>\n      <div class="mcq-opt" data-q="F28" data-val="3 days/week">3 days</div>\n      <div class="mcq-opt" data-q="F28" data-val="4 days/week">4 days</div>\n      <div class="mcq-opt" data-q="F28" data-val="5 days/week">5 days</div>\n      <div class="mcq-opt" data-q="F28" data-val="6 days/week">6 days</div>\n    </div>\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">F29</span><span class="q-text">How much time is available per training session?</span></div>\n    <div class="mcq-grid">\n      <div class="mcq-opt" data-q="F29" data-val="30 minutes per session">30 min</div>\n      <div class="mcq-opt" data-q="F29" data-val="45 minutes per session">45 min</div>\n      <div class="mcq-opt" data-q="F29" data-val="60 minutes per session">60 min</div>\n      <div class="mcq-opt" data-q="F29" data-val="90 minutes per session">90 min</div>\n    </div>\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">F30</span><span class="q-text">What is your dietary pattern?</span></div>\n    <div class="mcq-grid single">\n      <div class="mcq-opt" data-q="F30" data-val="Non-vegetarian (eats meat, chicken, fish, eggs)">Non-vegetarian — meat, chicken, fish, eggs</div>\n      <div class="mcq-opt" data-q="F30" data-val="Eggetarian (vegetarian + eggs)">Eggetarian — vegetarian + eggs</div>\n      <div class="mcq-opt" data-q="F30" data-val="Vegetarian (no meat, no eggs, dairy ok)">Vegetarian — dairy ok, no eggs</div>\n      <div class="mcq-opt" data-q="F30" data-val="Vegan (no animal products at all)">Vegan — no animal products</div>\n    </div>\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">F31</span><span class="q-text">Any food allergies or intolerances?</span></div>\n    <input type="text" id="F31" placeholder="e.g. Lactose intolerant, nut allergy... or \'None\'">\n  </div>\n\n  <div class="q-card">\n    <div class="q-label"><span class="q-num">F32</span><span class="q-text">Are you open to basic supplements? (Whey, Creatine, Vitamin D)</span></div>\n    <div class="mcq-grid single">\n      <div class="mcq-opt" data-q="F32" data-val="Yes — open to supplements, budget under ₹500/month">Yes — budget under ₹500/month</div>\n      <div class="mcq-opt" data-q="F32" data-val="Yes — open to supplements, budget ₹500–₹1500/month">Yes — budget ₹500–₹1500/month</div>\n      <div class="mcq-opt" data-q="F32" data-val="Yes — open to supplements, no strict budget">Yes — no strict budget</div>\n      <div class="mcq-opt" data-q="F32" data-val="No — prefer food-only approach, no supplements">No — food-only approach</div>\n    </div>\n  </div>\n\n  <div class="nav-row">\n    <button class="btn btn-outline" onclick="goSection(4)">← Back</button>\n    <span class="step-indicator">Section 6 of 6</span>\n    <button class="btn btn-primary" onclick="if(validateSection(5)) generateResult()">Generate My Blueprint →</button>\n  </div>\n</div>\n\n<!-- RESULT SCREEN -->\n<div id="result-screen">\n  <div class="eyebrow" style="font-size:11px;letter-spacing:.2em;text-transform:uppercase;color:var(--gold);margin-bottom:.75rem;font-family:\'DM Sans\',sans-serif;">Assessment Complete</div>\n  <h2>Your Blueprint Data<br><em style="font-style:italic;color:var(--muted);">is ready</em></h2>\n  <p class="sub">Copy the text below and paste it into Claude with the 12-month plan prompt.</p>\n  <pre id="output-box"></pre>\n  <div class="copy-row">\n    <button id="copy-btn" onclick="copyOutput()">Copy to Clipboard</button>\n    <button id="restart-btn" onclick="restartQuiz()">Start Over</button>\n    <button id="clear-form-btn" onclick="clearForm()">Clear Form</button>\n  </div>\n  <div class="disclaimer" style="margin-top:1.5rem;"><strong>Next step:</strong> Open Claude.ai → start a new chat → paste the copied text and add: <em>"Generate my complete personalised 12-month workout and nutrition plan based on this assessment."</em></div>\n</div>\n\n</main>\n\n<script>\nlet answers = JSON.parse(localStorage.getItem(\'blueprintAnswers\') || \'{}\');\nlet currentSection = 0;\nconst totalSections = 6;\n\nfunction saveAnswers() {\n  localStorage.setItem(\'blueprintAnswers\', JSON.stringify(answers));\n}\n\n// Build multi-select for conditions\nconst conditions = [\n  \'None / No diagnosed conditions\',\n  \'Hypertension (High BP)\',\n  \'Type 2 Diabetes or Pre-diabetes\',\n  \'Hypothyroidism\',\n  \'Hyperthyroidism\',\n  \'PCOD / PCOS\',\n  \'High cholesterol\',\n  \'Asthma\',\n  \'Heart condition\',\n  \'Lower back pain (chronic)\',\n  \'Knee pain or injury\',\n  \'Shoulder pain or impingement\',\n  \'Flat feet / ankle issues\'\n];\nconst c11Container = document.getElementById(\'C11-multi\');\nconditions.forEach(c => {\n  const d = document.createElement(\'div\');\n  d.className = \'mcq-opt\';\n  d.textContent = c;\n  if(c === \'None / No diagnosed conditions\') d.setAttribute(\'data-none\', \'true\');\n  d.addEventListener(\'click\', () => {\n    if (c === \'None / No diagnosed conditions\') {\n      c11Container.querySelectorAll(\'.mcq-opt\').forEach(el => el.classList.remove(\'selected\'));\n      d.classList.toggle(\'selected\');\n    } else {\n      c11Container.querySelector(\'[data-none]\')?.classList.remove(\'selected\');\n      d.classList.toggle(\'selected\');\n    }\n    const selected = [...c11Container.querySelectorAll(\'.selected\')].map(el => el.textContent);\n    answers[\'C11\'] = selected.join(\', \') || \'\';\n    saveAnswers();\n  });\n  c11Container.appendChild(d);\n});\n\n// Build multi-select for body parts\nconst bodyParts = [\'Arms / Biceps / Triceps\',\'Chest\',\'Shoulders\',\'Back (upper + lower)\',\'Core / Abs\',\'Legs / Quads / Hamstrings\',\'Glutes\',\'Overall fat loss\',\'Overall muscle mass\'];\nconst e25Container = document.getElementById(\'E25-multi\');\nbodyParts.forEach(bp => {\n  const d = document.createElement(\'div\');\n  d.className = \'mcq-opt\';\n  d.textContent = bp;\n  d.addEventListener(\'click\', () => {\n    d.classList.toggle(\'selected\');\n    const selected = [...e25Container.querySelectorAll(\'.selected\')].map(el => el.textContent);\n    answers[\'E25\'] = selected.join(\', \') || \'\';\n    saveAnswers();\n  });\n  e25Container.appendChild(d);\n});\n\n// Build scale buttons\nfunction buildScale(id, qKey) {\n  const wrap = document.getElementById(id);\n  for (let i = 1; i <= 5; i++) {\n    const btn = document.createElement(\'div\');\n    btn.className = \'scale-btn\';\n    btn.textContent = i;\n    btn.addEventListener(\'click\', () => {\n      wrap.querySelectorAll(\'.scale-btn\').forEach(b => b.classList.remove(\'selected\'));\n      btn.classList.add(\'selected\');\n      answers[qKey] = i + \'/5\';\n      saveAnswers();\n    });\n    wrap.appendChild(btn);\n  }\n}\nbuildScale(\'scale-C16\', \'C16\');\nbuildScale(\'scale-C17\', \'C17\');\n\n// MCQ single select\ndocument.querySelectorAll(\'.mcq-opt[data-q]\').forEach(opt => {\n  opt.addEventListener(\'click\', () => {\n    const q = opt.getAttribute(\'data-q\');\n    document.querySelectorAll(`.mcq-opt[data-q="${q}"]`).forEach(o => o.classList.remove(\'selected\'));\n    opt.classList.add(\'selected\');\n    answers[q] = opt.getAttribute(\'data-val\');\n    saveAnswers();\n  });\n});\n\n// Text inputs\nconst textInputs = [\'A1\',\'A2\',\'A4\',\'B5\',\'C12\',\'C13\',\'D20\',\'D21\',\'E24\',\'F31\'];\ntextInputs.forEach(id => {\n  const el = document.getElementById(id);\n  if (el) el.addEventListener(\'input\', () => { \n    answers[id] = el.value; \n    saveAnswers(); \n  });\n});\ndocument.getElementById(\'C11-other\').addEventListener(\'input\', function() {\n  answers[\'C11-extra\'] = this.value;\n  saveAnswers();\n});\n\n// Validate specific section\nfunction validateSection(idx) {\n  const sectionFields = [\n    [\'A1\', \'A2\', \'A3\', \'A4\'],\n    [\'B5\', \'B6\', \'B7\', \'B8\', \'B9\', \'B10\'],\n    [\'C11\', \'C12\', \'C13\', \'C14\', \'C15\', \'scale-C16\', \'scale-C17\'],\n    [\'D18\', \'D19\', \'D20\', \'D21\'],\n    [\'E22\', \'E23\', \'E24\', \'E25\', \'E26\'],\n    [\'F27\', \'F28\', \'F29\', \'F30\', \'F31\', \'F32\']\n  ];\n  \n  const fields = sectionFields[idx];\n  let isValid = true;\n  \n  fields.forEach(f => {\n    let qCard = null;\n    let fieldValid = true;\n    \n    if (f === \'A2\') {\n        let el = document.getElementById(f);\n        if(el) qCard = el.closest(\'.q-card\');\n        if (!answers[f] || String(answers[f]).trim() === \'\') {\n            fieldValid = false;\n        } else {\n            let age = parseInt(answers[f], 10);\n            if(isNaN(age) || age < 13 || age > 80) fieldValid = false;\n        }\n    } else if (f === \'B5\') {\n        let el = document.getElementById(f);\n        if(el) qCard = el.closest(\'.q-card\');\n        if (!answers[f] || String(answers[f]).trim() === \'\') {\n            fieldValid = false;\n        } else {\n            if (!/\\d+/.test(answers[f])) fieldValid = false;\n        }\n    } else if (textInputs.includes(f)) {\n        let el = document.getElementById(f);\n        if(el) qCard = el.closest(\'.q-card\');\n        if (!answers[f] || String(answers[f]).trim() === \'\') fieldValid = false;\n    } else if (f === \'C11\' || f === \'E25\') {\n        let multiEl = document.getElementById(f + \'-multi\');\n        if(multiEl) qCard = multiEl.closest(\'.q-card\');\n        let hasExtra = f === \'C11\' && answers[\'C11-extra\'] && answers[\'C11-extra\'].trim() !== \'\';\n        if ((!answers[f] || String(answers[f]).trim() === \'\') && !hasExtra) fieldValid = false;\n    } else if (f.startsWith(\'scale-\')) {\n        let idKey = f.replace(\'scale-\', \'\');\n        let el = document.getElementById(f);\n        if(el) qCard = el.closest(\'.q-card\');\n        if (!answers[idKey]) fieldValid = false;\n    } else {\n        let mcqOpt = document.querySelector(`.mcq-opt[data-q="${f}"]`);\n        if(mcqOpt) qCard = mcqOpt.closest(\'.q-card\');\n        if (!answers[f]) fieldValid = false;\n    }\n    \n    if (!fieldValid && qCard) {\n        qCard.classList.remove(\'invalid\');\n        void qCard.offsetWidth; // trigger reflow\n        qCard.classList.add(\'invalid\');\n        isValid = false;\n    } else if (qCard) {\n        qCard.classList.remove(\'invalid\');\n    }\n  });\n\n  return isValid;\n}\n\nfunction goSection(idx) {\n  document.querySelectorAll(\'.section-block\').forEach((b, i) => {\n    b.classList.toggle(\'visible\', i === idx);\n  });\n  document.querySelectorAll(\'.sec-tab\').forEach((t, i) => {\n    t.classList.toggle(\'active\', i === idx);\n  });\n  currentSection = idx;\n  updateProgress();\n  window.scrollTo({ top: 0, behavior: \'smooth\' });\n}\n\nfunction updateProgress() {\n  const pct = ((currentSection) / totalSections) * 100;\n  document.getElementById(\'progress-fill\').style.width = pct + \'%\';\n}\n\nfunction generateResult() {\n  // Collect remaining text inputs just in case\n  textInputs.forEach(id => {\n    const el = document.getElementById(id);\n    if (el && !answers[id]) answers[id] = el.value || \'Not provided\';\n  });\n  if (!answers[\'C11-extra\']) answers[\'C11-extra\'] = document.getElementById(\'C11-other\').value || \'\';\n  \n  saveAnswers();\n\n  const out = `BLUEPRINT FITNESS ASSESSMENT — CLIENT DATA\n==========================================\n\nSECTION A — PERSONAL IDENTITY\nA1 Name: ${answers[\'A1\'] || \'Not provided\'}\nA2 Age: ${answers[\'A2\'] || \'Not provided\'}\nA3 Biological Sex: ${answers[\'A3\'] || \'Not provided\'}\nA4 Location / Climate: ${answers[\'A4\'] || \'Not provided\'}\n\nSECTION B — BODY TYPE SELF-ASSESSMENT\nB5 Height & Weight: ${answers[\'B5\'] || \'Not provided\'}\nB6 Wrist Size: ${answers[\'B6\'] || \'Not provided\'}\nB7 Shoulder-to-Hip Ratio: ${answers[\'B7\'] || \'Not provided\'}\nB8 Fat Storage Area: ${answers[\'B8\'] || \'Not provided\'}\nB9 Response to Overeating: ${answers[\'B9\'] || \'Not provided\'}\nB10 Natural Frame: ${answers[\'B10\'] || \'Not provided\'}\n\nSECTION C — MEDICAL HISTORY & HEALTH CONCERNS\nC11 Diagnosed Conditions: ${answers[\'C11\'] || \'None\'}${answers[\'C11-extra\'] ? \' | Additional: \' + answers[\'C11-extra\'] : \'\'}\nC12 Past / Current Injuries: ${answers[\'C12\'] || \'Not provided\'}\nC13 Current Medications: ${answers[\'C13\'] || \'Not provided\'}\nC14 Recent Surgeries: ${answers[\'C14\'] || \'Not provided\'}\nC15 Pregnancy / Postpartum: ${answers[\'C15\'] || \'Not provided\'}\nC16 Daily Energy Level: ${answers[\'C16\'] || \'Not provided\'}\nC17 Sleep Quality: ${answers[\'C17\'] || \'Not provided\'}\n\nSECTION D — CURRENT FITNESS STATUS\nD18 Training Experience: ${answers[\'D18\'] || \'Not provided\'}\nD19 Daily Activity Level: ${answers[\'D19\'] || \'Not provided\'}\nD20 Current Exercise Habits: ${answers[\'D20\'] || \'Not provided\'}\nD21 Past Programs & Results: ${answers[\'D21\'] || \'Not provided\'}\n\nSECTION E — GOALS & TIMELINE\nE22 Primary Goal: ${answers[\'E22\'] || \'Not provided\'}\nE23 Target Timeline: ${answers[\'E23\'] || \'Not provided\'}\nE24 Specific Event / Deadline: ${answers[\'E24\'] || \'Not provided\'}\nE25 Priority Body Parts: ${answers[\'E25\'] || \'Not provided\'}\nE26 Expectation Acknowledgment: ${answers[\'E26\'] || \'Not provided\'}\n\nSECTION F — LIFESTYLE & CONVENIENCE\nF27 Equipment / Gym Access: ${answers[\'F27\'] || \'Not provided\'}\nF28 Training Days per Week: ${answers[\'F28\'] || \'Not provided\'}\nF29 Time per Session: ${answers[\'F29\'] || \'Not provided\'}\nF30 Dietary Pattern: ${answers[\'F30\'] || \'Not provided\'}\nF31 Allergies / Intolerances: ${answers[\'F31\'] || \'Not provided\'}\nF32 Supplement Openness: ${answers[\'F32\'] || \'Not provided\'}\n\n==========================================\nEND OF ASSESSMENT`;\n\n  document.getElementById(\'output-box\').textContent = out;\n  document.querySelectorAll(\'.section-block\').forEach(b => b.classList.remove(\'visible\'));\n  document.getElementById(\'result-screen\').style.display = \'block\';\n  document.getElementById(\'progress-fill\').style.width = \'100%\';\n  window.scrollTo({ top: 0, behavior: \'smooth\' });\n}\n\nfunction copyOutput() {\n  const text = document.getElementById(\'output-box\').textContent;\n  navigator.clipboard.writeText(text).then(() => {\n    const btn = document.getElementById(\'copy-btn\');\n    btn.textContent = \'Copied!\';\n    btn.classList.add(\'copied\');\n    setTimeout(() => { btn.textContent = \'Copy to Clipboard\'; btn.classList.remove(\'copied\'); }, 2500);\n  });\n}\n\nfunction restartQuiz() {\n  document.getElementById(\'result-screen\').style.display = \'none\';\n  goSection(0);\n}\n\nfunction clearForm() {\n  answers = {};\n  saveAnswers();\n  // Clear UI\n  document.querySelectorAll(\'.mcq-opt\').forEach(o => o.classList.remove(\'selected\'));\n  document.querySelectorAll(\'input[type=text], input[type=number], textarea\').forEach(el => el.value = \'\');\n  document.querySelectorAll(\'.scale-btn\').forEach(b => b.classList.remove(\'selected\'));\n  document.querySelectorAll(\'.invalid\').forEach(el => el.classList.remove(\'invalid\'));\n  \n  document.getElementById(\'result-screen\').style.display = \'none\';\n  goSection(0);\n}\n\n// Load Answers on startup\nfunction loadAnswers() {\n  // text inputs\n  textInputs.forEach(id => {\n    const el = document.getElementById(id);\n    if (el && answers[id] !== undefined) {\n      el.value = answers[id];\n    }\n  });\n\n  if (answers[\'C11-extra\'] !== undefined) {\n    const el = document.getElementById(\'C11-other\');\n    if (el) el.value = answers[\'C11-extra\'];\n  }\n\n  // MCQs\n  document.querySelectorAll(\'.mcq-opt[data-q]\').forEach(opt => {\n    const q = opt.getAttribute(\'data-q\');\n    if (answers[q] === opt.getAttribute(\'data-val\')) {\n      opt.classList.add(\'selected\');\n    }\n  });\n\n  // Multiselect C11\n  if (answers[\'C11\']) {\n    const arr = answers[\'C11\'].split(\', \');\n    c11Container.querySelectorAll(\'.mcq-opt\').forEach(opt => {\n      if (arr.includes(opt.textContent)) {\n        opt.classList.add(\'selected\');\n      }\n    });\n  }\n\n  // Multiselect E25\n  if (answers[\'E25\']) {\n    const arr = answers[\'E25\'].split(\', \');\n    e25Container.querySelectorAll(\'.mcq-opt\').forEach(opt => {\n      if (arr.includes(opt.textContent)) {\n        opt.classList.add(\'selected\');\n      }\n    });\n  }\n\n  // Scales\n  [\'C16\', \'C17\'].forEach(qKey => {\n    if (answers[qKey]) {\n      const val = answers[qKey].split(\'/\')[0];\n      const wrap = document.getElementById(\'scale-\' + qKey);\n      if (wrap) {\n        wrap.querySelectorAll(\'.scale-btn\').forEach(btn => {\n          if (btn.textContent === val) btn.classList.add(\'selected\');\n        });\n      }\n    }\n  });\n}\n\nloadAnswers();\nupdateProgress();\n</script>\n</body>\n</html>\n')